function awardForCompletion({ levelId, score, timeSeconds, attempt, isFirstClear, isNewBestScore, isNewBestTime }) {
  const rewards = {
    coins: 0,
    gems: 0,
    items: {},
    tags: [],
  };

  // Base coins for completion
  rewards.coins += 50;

  // Score-based coins (client-reported)
  // 0..MAX_SCORE -> 0..500
  const scoreCoins = Math.floor(Math.min(500, (score / MAX_SCORE) * 500));
  rewards.coins += scoreCoins;

  // Time-based bonus: faster -> more coins
  // 0..MAX_TIME_SECONDS -> 200..0
  const timeBonus = Math.floor(Math.max(0, 200 - (timeSeconds / 60) * 10)); // -10 per minute
  rewards.coins += timeBonus;

  // First clear bonus
  if (isFirstClear) {
    rewards.coins += 200;
    rewards.gems += 1;
    rewards.tags.push('first_clear');
  }

  // New best bonuses
  if (isNewBestScore) {
    rewards.coins += 100;
    rewards.tags.push('new_best_score');
  }
  if (isNewBestTime) {
    rewards.coins += 100;
    rewards.tags.push('new_best_time');
  }

  // Streak/attempt modifier (discourage farming by repeated attempts)
  // attempt starts at 1; reduce coins after many attempts
  if (attempt >= 6) rewards.coins = Math.floor(rewards.coins * 0.8);
  if (attempt >= 11) rewards.coins = Math.floor(rewards.coins * 0.6);

  // Level milestone gems
  if (levelId % 10 === 0) rewards.gems += 1;

  // Small chance item (deterministic-ish based on metrics)
  const seed = crypto.createHash('sha256').update(`${levelId}|${score}|${timeSeconds}|${attempt}`).digest();
  const roll = seed.readUInt32BE(0) / 0xffffffff;
  if (roll < 0.05) {
    rewards.items['hint'] = (rewards.items['hint'] || 0) + 1;
    rewards.tags.push('bonus_item_hint');
  }

  // Ensure non-negative integers
  rewards.coins = Math.max(0, Math.trunc(rewards.coins));
  rewards.gems = Math.max(0, Math.trunc(rewards.gems));
  return rewards;
}

function applyReward(player, reward) {
  player.currency.coins += reward.coins || 0;
  player.currency.gems += reward.gems || 0;
  if (reward.items && typeof reward.items === 'object') {
    for (const [k, v] of Object.entries(reward.items)) {
      if (!Number.isFinite(v)) continue;
      const add = Math.max(0, Math.trunc(v));
      if (!add) continue;
      player.inventory[k] = (player.inventory[k] || 0) + add;
    }
  }
}

function sanitizeCompletionBody(body) {
  if (!body || typeof body !== 'object') return { ok: false, error: 'invalid_body' };

  const playerId = body.playerId;
  if (!isValidId(playerId)) return { ok: false, error: 'invalid_playerId' };

  const levelId = clampInt(body.levelId, 1, MAX_LEVEL_ID);
  if (levelId === null) return { ok: false, error: 'invalid_levelId' };

  const score = clampInt(body.score, 0, MAX_SCORE);
  if (score === null) return { ok: false, error: 'invalid_score' };

  const timeSeconds = clampNumber(body.timeSeconds, 0, MAX_TIME_SECONDS);
  if (timeSeconds === null) return { ok: false, error: 'invalid_timeSeconds' };

  const clientTs = body.clientTs;
  const clientTsNum = clampInt(clientTs, 0, 4102444800); // up to year 2100
  if (clientTsNum === null) return { ok: false, error: 'invalid_clientTs' };

  const sessionId = body.sessionId;
  if (!isValidId(sessionId)) return { ok: false, error: 'invalid_sessionId' };

  const attempt = clampInt(body.attempt || 1, 1, 1000);
  if (attempt === null) return { ok: false, error: 'invalid_attempt' };

  return {
    ok: true,
    data: { playerId, levelId, score, timeSeconds, clientTs: clientTsNum, sessionId, attempt },
  };
}

