app.post('/v1/levels/complete', requireApiKey, (req, res) => {
  const parsed = sanitizeCompletionBody(req.body);
  if (!parsed.ok) return jsonError(res, 400, 'BAD_REQUEST', parsed.error);

  const proofCheck = verifyClientProof(req.body);
  if (!proofCheck.ok) return jsonError(res, 400, 'BAD_REQUEST', 'Invalid proof', { reason: proofCheck.reason });

  const { playerId, levelId, score, timeSeconds, clientTs, sessionId, attempt } = parsed.data;

  // Ensure proof payload matches key fields to prevent trivial tampering
  const expectedPayload = {
    playerId,
    levelId,
    score,
    timeSeconds,
    clientTs,
    sessionId,
    attempt,
  };
  const proofPayload = proofCheck.payload;
  if (stableStringify(proofPayload) !== stableStringify(expectedPayload)) {
    return jsonError(res, 400, 'BAD_REQUEST', 'Proof payload mismatch');
  }

  const player = getOrCreatePlayer(playerId);

  const prev = player.completedLevels.get(levelId);
  const isFirstClear = !prev;
  const prevBestScore = prev ? prev.bestScore : -1;
  const prevBestTime = prev ? prev.bestTimeSeconds : Infinity;

  const isNewBestScore = score > prevBestScore;
  const isNewBestTime = timeSeconds < prevBestTime;

  const completion = {
    levelId,
    lastCompletedAt: nowMs(),
    sessionId,
    clientTs,
    attempts: prev ? Math.max(prev.attempts, attempt) : attempt,
    bestScore: isNewBestScore ? score : prev.bestScore,
    bestTimeSeconds: isNewBestTime ? timeSeconds : prev.bestTimeSeconds,
    lastScore: score,
    lastTimeSeconds: timeSeconds,
    clears: (prev ? prev.clears : 0) + 1,
  };

  player.completedLevels.set(levelId, completion);

  const reward = awardForCompletion({
    levelId,
    score,
    timeSeconds,
    attempt,
    isFirstClear,
    isNewBestScore,
    isNewBestTime,
  });

  const rewardId = makeRewardId();
  const pending = {
    rewardId,
    playerId,
    levelId,
    createdAt: nowMs(),
    status: 'pending',
    reward,
    meta: {
      score,
      timeSeconds,
      attempt,
      isFirstClear,
      isNewBestScore,
      isNewBestTime,
    },
  };

  player.pendingRewards.set(rewardId, pending);

  res.json({
    ok: true,
    completion: {
      levelId,
      score,
      timeSeconds,
      isFirstClear,
      isNewBestScore,
      isNewBestTime,
    },
    pendingReward: {
      rewardId,
      reward,
    },
  });
});

app.post('/v1/rewards/claim', requireApiKey, (req, res) => {
  const body = req.body || {};
  const playerId = body.playerId;
  const rewardId = body.rewardId;

  if (!isValidId(playerId)) return jsonError(res, 400, 'BAD_REQUEST', 'invalid_playerId');
  if (!isValidId(rewardId)) return jsonError(res, 400, 'BAD_REQUEST', 'invalid_rewardId');

  const player = getOrCreatePlayer(playerId);
  const pending = player.pendingRewards.get(rewardId);
  if (!pending) return jsonError(res, 404, 'NOT_FOUND', 'Reward not found');
  if (pending.playerId !== playerId) return jsonError(res, 403, 'FORBIDDEN', 'Reward does not belong to player');
  if (pending.status !== 'pending') return jsonError(res, 409, 'CONFLICT', 'Reward already claimed');

  // Optional idempotency token
  const idempotencyKey = req.header('idempotency-key');
  if (idempotencyKey && typeof idempotencyKey === 'string') {
    if (pending.idempotencyKey && pending.idempotencyKey !== idempotencyKey) {
      return jsonError(res, 409, 'CONFLICT', 'Idempotency key mismatch');
    }
    pending.idempotencyKey = idempotencyKey;
  }

  pending.status = 'claimed';
  pending.claimedAt = nowMs();

  applyReward(player, pending.reward);

  res.json({
    ok: true,
    claimed: {
      rewardId,
      levelId: pending.levelId,
      reward: pending.reward,
      claimedAt: pending.claimedAt,
    },
    balances: player.currency,
    inventory: player.inventory,
  });
});

app.get('/v1/players/:playerId/state', requireApiKey, (req, res) => {
  const playerId = req.params.playerId;
  if (!isValidId(playerId)) return jsonError(res, 400, 'BAD_REQUEST', 'invalid_playerId');
  const player = getOrCreatePlayer(playerId);

  const completed = [];
  for (const [levelId, c] of player.completedLevels.entries()) {
    completed.push({
      levelId,
      bestScore: c.bestScore,
      bestTimeSeconds: c.bestTimeSeconds,
      clears: c.clears,
      lastCompletedAt: c.lastCompletedAt,
    });
  }
  completed.sort((a, b) => a.levelId - b.levelId);

  const pendingRewards = [];
  for (const [rewardId, r] of player.pendingRewards.entries()) {
    if (r.status === 'pending') pendingRewards.push({ rewardId, levelId: r.levelId, createdAt: r.createdAt, reward: r.reward });
  }
  pendingRewards.sort((a, b) => b.createdAt - a.createdAt);

  res.json({
    ok: true,
    player: {
      playerId,
      createdAt: player.createdAt,
      balances: player.currency,
      inventory: player.inventory,
      completedLevels: completed,
      pendingRewards,
    },
  });
});

